module freq_div (
    input CLK_in,
    input RST,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1
);

reg [2:0] counter_50;
reg [3:0] counter_10;
reg [6:0] counter_1;

always @(posedge CLK_in or negedge RST) begin
    if (!RST) begin
        counter_50 <= 0;
        counter_10 <= 0;
        counter_1 <= 0;
        CLK_50 <= 0;
        CLK_10 <= 0;
        CLK_1 <= 0;
    end else begin
        // 50MHz clock
        if (counter_50 == 4) begin
            counter_50 <= 0;
            CLK_50 <= ~CLK_50;
        end else begin
            counter_50 <= counter_50 + 1;
        end

        // 10MHz clock
        if (counter_10 == 9) begin
            counter_10 <= 0;
            CLK_10 <= ~CLK_10;
        end else begin
            counter_10 <= counter_10 + 1;
        end

        // 1MHz clock
        if (counter_1 == 99) begin
            counter_1 <= 0;
            CLK_1 <= ~CLK_1;
        end else begin
            counter_1 <= counter_1 + 1;
        end
    end
end

endmodule
